DOMAIN_SUMMARY = 'The legal compliance domain involves adhering to laws, regulations, and internal policies. Escalation triage specifically focuses on the initial assessment of reported compliance issues, determining their severity, responsible department, and next steps. This project simplifies this process by providing quick access to relevant policy information.'
USER_PERSONA = 'Junior Compliance Officer (JCO): A JCO is responsible for the initial review of reported compliance issues, policy inquiries, or potential violations. They need quick, accurate access to internal guidelines to categorize incidents, identify responsible parties, and understand escalation protocols. Their primary goal is efficient, consistent, and compliant triage.'
STARTER_QUESTIONS = ['What is the process for reporting a potential ethics violation?', 'Who should I contact for an HR compliance issue?', 'What steps are required for a data privacy breach escalation?', "Where can I find the company's anti-bribery policy?", 'How quickly must a serious compliance incident be reported?']
WORKFLOW_STEPS = ['**Step 1: Document Ingestion (Offline/Setup)**: Sample compliance documents are loaded, chunked into smaller passages, and converted into numerical embeddings.', '**Step 2: Vector Database Population (Offline/Setup)**: These embeddings are stored in the vector database, indexed for efficient semantic search.', "**Step 3: User Query (Online)**: A Junior Compliance Officer enters a question into the frontend (e.g., 'How do I report a conflict of interest?').", '**Step 4: Query Embedding (Backend)**: The backend API receives the query and converts it into a vector embedding using the same embedding model.', '**Step 5: Semantic Search (Backend + Vector DB)**: The query embedding is used to search the vector database for the most semantically similar document chunks.', '**Step 6: Context Retrieval (Backend)**: The top N (e.g., 3-5) most relevant document chunks are retrieved.', '**Step 7: Prompt Construction (Backend)**: These retrieved chunks are combined with the original user query and a system instruction into a concise prompt for the LLM.', '**Step 8: LLM Generation (Backend)**: The prompt is sent to the LLM, which generates a coherent and relevant answer based *only* on the provided context.']
BUSINESS_RULES = ['**Relevance First**: Answers must primarily rely on information retrieved from the provided compliance documents.', '**Conciseness**: Responses should be direct and to the point, avoiding unnecessary jargon.', '**Clarity**: Language used in responses should be easy for a JCO to understand.', '**Non-Discretionary**: The system should not offer legal advice or make subjective judgments; it only provides information based on policies.', '**Source Transparency (Recommended)**: If possible, indicate which document(s) or policy sections were used to formulate the answer.', '**Scope Limitation**: The system should acknowledge if a query is outside the scope of its knowledge base (i.e., no relevant documents found).']
TOOL_CATALOG = [{'name': 'documentsearch', 'description': 'Searches the internal policy document knowledge base for relevant information given a query.'}, {'name': 'compliancepolicylookup', 'description': 'Specifically designed to retrieve details about company policies related to ethics, reporting, or specific regulatory areas.'}]
